    def clear_folder(folder_path):   #清空文件夹
        import os, shutil
        if not os.path.exists(folder_path):
            return
        for f in os.listdir(folder_path):
            p = os.path.join(folder_path, f)
            if os.path.isfile(p) or os.path.islink(p):
                os.unlink(p)
            else:
                shutil.rmtree(p)
