    #保存图片
    def sftp_get_directory(self):
        # 建立SFTP连接
        remote_dir='/home/images'
        local_dir=r'\\wsl.localhost\Ubuntu-22.04\home\wensyu\DetectorFreeSfM\SfM_dataset\example_dataset\example_scene\images'
        image_dir=r'images'
        transport = paramiko.Transport(('192.168.137.129', 22))
        transport.connect(username='ubuntu', password='ubuntu')
        sftp = paramiko.SFTPClient.from_transport(transport)
        #保存文件夹中的每一张图片
        def download_dir(remote_dir, local_dir):
            if not os.path.exists(local_dir):
                os.makedirs(local_dir)
            for item in sftp.listdir_attr(remote_dir):
                remote_path = remote_dir + '/' + item.filename
                local_path = os.path.join(local_dir, item.filename)
                # if paramiko.S_ISDIR(item.st_mode):
                #     download_dir(remote_path, local_path)
                # else:
                sftp.get(remote_path, local_path)


        download_dir(remote_dir, local_dir)
        download_dir(remote_dir, image_dir)
        # 关闭SFTP连接
        sftp.close()
        transport.close()
        self.textBrowser.append("图片已保存到本地")



    #重建过程
    def reconstruction(self):
        res_dir = r'result/sparse'
        res_dense_dir = r'result/dense'
        if not os.path.exists(res_dense_dir):
            os.makedirs(res_dense_dir)
        #清空原来的文字
        self.textBrowser.clear()
        cmd = (
            'source /root/anaconda3/etc/profile.d/conda.sh && '
            'conda activate detectorfreesfm && '
            'cd /home/wensyu/DetectorFreeSfM && '
            'python eval_dataset.py +demo=dfsfm.yaml'
            # 'python eval_dataset.py'
        )
        #执行Python自动化脚本

       # srecon = subprocess.Popen([r"MvgMvsPipelineV1.py",
       #                                r"images",
       #                                r"res"], shell=True,stdout=subprocess.PIPE,text=True)

        #output, error = subprocess.communicate()
        srecon = subprocess.Popen(
        ["wsl", "-d", "Ubuntu-22.04", "bash", "-c", cmd],shell=True,stdout=subprocess.PIPE,text=True
       # check=True,
        #capture_output=True,
        #text=True,
        #encoding="utf-8",
        #errors="replace"
    )

    # output = srecon.stdout.read().decode()
        # self.printf(output)
        # srecon.wait()
        while True:
            output = srecon.stdout.readline()
            if output == '' and srecon.poll() is not None:
                break
            if output:
                self.printf(output.strip())

        #创建文件夹用于dfsfm->mvs
        if not os.path.exists(res_dir):
            os.makedirs(res_dir)
        else:
            shutil.rmtree(res_dir)
            os.makedirs(res_dir, exist_ok=True)

        #复制bin文件到此项目的res/sparse中
        src = Path(r"\\wsl.localhost\Ubuntu-22.04\home\wensyu\DetectorFreeSfM\SfM_dataset\example_dataset\example_scene\DetectorFreeSfM_loftr_official_coarse_fine__scratch_no_intrin\model_refined_0")
        dst = Path(r"result/sparse")

        dst.mkdir(parents=True, exist_ok=True)

        for item in src.iterdir():
            target = dst / item.name
            if item.is_dir():
                shutil.copytree(item, target, dirs_exist_ok=True)
            else:
                shutil.copy2(item, target)

        #用bin文件进行mvs
        p1 = subprocess.Popen(
            [
                r"bin\MVS\InterfaceCOLMAP.exe",
                "-i", r"result",
                "-o", r"result\sparse\res.mvs",
                "--image-folder", r"images"
            ],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True
        )
        p1.wait()

        p2 = subprocess.run(
            [r".\bin\MVS\DensifyPointCloud.exe",
             "-i", r"result\sparse\res.mvs",
             "-o", r"result\dense\dense_pointcloud"
             ],
            capture_output=True,
            text=True
        )
        p2.wait()




        self.textBrowser.append("Reconstruction finished!")

        srecon.wait()


    #显示点云
    def showply(self):
        ply_file_path = r"result\dense\dense_pointcloud.ply"
        point_cloud = o3d.io.read_point_cloud(ply_file_path)

        vis = o3d.visualization.Visualizer()
        vis.create_window(window_name='Point Cloud', width=1024, height=768)

        # 添加点云并渲染
        vis.add_geometry(point_cloud)
        vis.run()
        vis.destroy_window()


